import{_ as l,o as i,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2013年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2013年/核心总结.md","filePath":"01_letters/2013年/核心总结.md"}'),t={name:"01_letters/2013年/核心总结.md"};function o(h,a,n,u,d,s){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="_2013年巴菲特致股东信核心总结" tabindex="-1">2013年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2013年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2013年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长18.2%，低于标普500的32.4%</li><li>49年复合年增长率19.7%</li><li>净资产增长342亿美元</li><li>连续11年承保盈利，累计220亿美元</li></ul><h2 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h2><h3 id="亨氏收购完成" tabindex="-1">亨氏收购完成 <a class="header-anchor" href="#亨氏收购完成" aria-label="Permalink to &quot;亨氏收购完成&quot;">​</a></h3><ul><li>6月取得控制权</li><li>与3G资本合作模式</li><li>伯克希尔投资80亿美元优先股+42.5亿美元普通股</li><li>优先股年回报率约12%</li></ul><h3 id="nv-energy收购" tabindex="-1">NV Energy收购 <a class="header-anchor" href="#nv-energy收购" aria-label="Permalink to &quot;NV Energy收购&quot;">​</a></h3><ul><li>MidAmerican以56亿美元收购</li><li>服务内华达州88%人口</li><li>提供可再生能源投资机会</li></ul><h3 id="marmon和iscar增资" tabindex="-1">Marmon和Iscar增资 <a class="header-anchor" href="#marmon和iscar增资" aria-label="Permalink to &quot;Marmon和Iscar增资&quot;">​</a></h3><ul><li>购买Marmon剩余股权（100%所有权）</li><li>Iscar Wertheimer家族行使看跌期权出售20%股权</li><li>增加约3亿美元税前利润</li></ul><h2 id="五大业务表现" tabindex="-1">五大业务表现 <a class="header-anchor" href="#五大业务表现" aria-label="Permalink to &quot;五大业务表现&quot;">​</a></h2><h3 id="五大支柱" tabindex="-1">&quot;五大支柱&quot; <a class="header-anchor" href="#五大支柱" aria-label="Permalink to &quot;&quot;五大支柱&quot;&quot;">​</a></h3><ul><li>BNSF、Iscar、Lubrizol、Marmon、MidAmerican Energy</li><li>合计税前利润108亿美元，创纪录</li><li>2014年预计增加约10亿美元</li></ul><h3 id="补强收购" tabindex="-1">补强收购 <a class="header-anchor" href="#补强收购" aria-label="Permalink to &quot;补强收购&quot;">​</a></h3><ul><li>签约25笔，总成本31亿美元</li><li>规模从190万美元到11亿美元</li></ul><h2 id="资本支出" tabindex="-1">资本支出 <a class="header-anchor" href="#资本支出" aria-label="Permalink to &quot;资本支出&quot;">​</a></h2><ul><li>创纪录的110亿美元</li><li>89%投放在美国</li><li>BNSF投入40亿美元</li></ul><h2 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h2><h3 id="四大-投资" tabindex="-1">&quot;四大&quot;投资 <a class="header-anchor" href="#四大-投资" aria-label="Permalink to &quot;&quot;四大&quot;投资&quot;">​</a></h3><ul><li>美国运通、可口可乐、IBM、富国银行</li><li>持股比例每增加0.1%，年利润增加5000万美元</li><li>未报告利润30亿美元与报告利润同样有价值</li></ul><h3 id="新增持仓" tabindex="-1">新增持仓 <a class="header-anchor" href="#新增持仓" aria-label="Permalink to &quot;新增持仓&quot;">​</a></h3><ul><li>Exxon Mobil（埃克森美孚）</li><li>削减Tesco持仓</li></ul><h2 id="关键投资理念" tabindex="-1">关键投资理念 <a class="header-anchor" href="#关键投资理念" aria-label="Permalink to &quot;关键投资理念&quot;">​</a></h2><h3 id="农场投资案例-1986年" tabindex="-1">农场投资案例（1986年） <a class="header-anchor" href="#农场投资案例-1986年" aria-label="Permalink to &quot;农场投资案例（1986年）&quot;">​</a></h3><ul><li>以28万美元购买400英亩农场</li><li>正常化回报率约10%</li><li>28年后利润增加两倍，价值增加五倍以上</li></ul><h3 id="纽约大学附近零售物业-1993年" tabindex="-1">纽约大学附近零售物业（1993年） <a class="header-anchor" href="#纽约大学附近零售物业-1993年" aria-label="Permalink to &quot;纽约大学附近零售物业（1993年）&quot;">​</a></h3><ul><li>无杠杆当期收益率约10%</li><li>位置极佳：纽约大学不会搬走</li><li>现在年度分配超过原始投资35%</li></ul><h3 id="投资基本原则" tabindex="-1">投资基本原则 <a class="header-anchor" href="#投资基本原则" aria-label="Permalink to &quot;投资基本原则&quot;">​</a></h3><ol><li>不需要成为专家也能获得满意回报</li><li>关注资产未来生产力，不关注价格变化</li><li>专注于拟购买的预期价格变化是投机</li><li>形成宏观观点是浪费时间</li><li>比赛由专注于球场的球员赢得</li></ol><h3 id="对非专业投资者的建议" tabindex="-1">对非专业投资者的建议 <a class="header-anchor" href="#对非专业投资者的建议" aria-label="Permalink to &quot;对非专业投资者的建议&quot;">​</a></h3><ul><li>持有标普500指数基金</li><li>长期持有，不在市场下跌时恐慌</li><li>忽略噪音，保持成本最低</li><li>股价下跌对长期净买家是好事</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金的价值" tabindex="-1">浮存金的价值 <a class="header-anchor" href="#浮存金的价值" aria-label="Permalink to &quot;浮存金的价值&quot;">​</a></h3><ul><li>49年增长至772亿美元</li><li>连续11年承保盈利，累计220亿美元</li><li>无成本浮存金的价值远超账面记录</li></ul><h3 id="新业务-bhsi" tabindex="-1">新业务：BHSI <a class="header-anchor" href="#新业务-bhsi" aria-label="Permalink to &quot;新业务：BHSI&quot;">​</a></h3><ul><li>伯克希尔哈撒韦专业保险公司</li><li>由Peter Eastwood领导</li><li>立即被主要保险经纪人和企业接受</li></ul><h2 id="亨氏合作模式的意义" tabindex="-1">亨氏合作模式的意义 <a class="header-anchor" href="#亨氏合作模式的意义" aria-label="Permalink to &quot;亨氏合作模式的意义&quot;">​</a></h2><ul><li>伯克希尔作为融资合作伙伴</li><li>3G负责运营（Alex Behring任董事长，Bernardo Hees任CEO）</li><li>双方各出资42.5亿美元普通股</li><li>优先股提供稳定收益+认股权证</li></ul><h2 id="生产力与繁荣" tabindex="-1">生产力与繁荣 <a class="header-anchor" href="#生产力与繁荣" aria-label="Permalink to &quot;生产力与繁荣&quot;">​</a></h2><h3 id="农业革命案例" tabindex="-1">农业革命案例 <a class="header-anchor" href="#农业革命案例" aria-label="Permalink to &quot;农业革命案例&quot;">​</a></h3><ul><li>1900年：40%劳动力从事农业</li><li>现在：2%劳动力生产更多粮食</li><li>生产力提升释放人力到其他领域</li></ul><h3 id="bnsf效率提升" tabindex="-1">BNSF效率提升 <a class="header-anchor" href="#bnsf效率提升" aria-label="Permalink to &quot;BNSF效率提升&quot;">​</a></h3><ul><li>1996年：4.11亿吨英里，45,000员工</li><li>2013年：7.02亿吨英里，47,000员工</li><li>安全记录改善超过50%</li></ul><h2 id="geico的成长" tabindex="-1">GEICO的成长 <a class="header-anchor" href="#geico的成长" aria-label="Permalink to &quot;GEICO的成长&quot;">​</a></h2><ul><li>1951年首次接触时的震撼</li><li>成本优势是护城河</li><li>托尼·奈斯利1993年接手后的持续增长</li><li>目标：成为行业第一</li></ul><h2 id="企业文化特点" tabindex="-1">企业文化特点 <a class="header-anchor" href="#企业文化特点" aria-label="Permalink to &quot;企业文化特点&quot;">​</a></h2><ul><li>24人总部管理330,745名员工</li><li>以股东为导向的文化</li><li>管理者以所有者心态运营</li><li>无官僚委员会</li></ul><h2 id="重要风险警示" tabindex="-1">重要风险警示 <a class="header-anchor" href="#重要风险警示" aria-label="Permalink to &quot;重要风险警示&quot;">​</a></h2><h3 id="网络与大规模破坏性攻击" tabindex="-1">网络与大规模破坏性攻击 <a class="header-anchor" href="#网络与大规模破坏性攻击" aria-label="Permalink to &quot;网络与大规模破坏性攻击&quot;">​</a></h3><ul><li>对伯克希尔的重大威胁</li><li>也是美国公民面临的主要威胁</li><li>公司或投资者无法规避此风险</li></ul><h3 id="气候变化" tabindex="-1">气候变化 <a class="header-anchor" href="#气候变化" aria-label="Permalink to &quot;气候变化&quot;">​</a></h3><ul><li>作为公民应关注</li><li>作为保险公司股东不必担心</li><li>保险合同每年重新定价</li></ul><h2 id="美国经济展望" tabindex="-1">美国经济展望 <a class="header-anchor" href="#美国经济展望" aria-label="Permalink to &quot;美国经济展望&quot;">​</a></h2><ul><li>押注美国繁荣是确定的事</li><li>238年无人因做空美国获益</li><li>内在价值每年都能增长</li><li>投资于美国企业是最安全的选择</li></ul>',54)])])}const b=l(t,[["render",o]]);export{q as __pageData,b as default};
